@MainActor
final class ClipboardScope {
    private let savedClipboard: [NSPasteboard.PasteboardType: Data]
    private let pasteboard: PasteboardProvider

    init(pasteboard: PasteboardProvider? = nil) {
        let resolvedPasteboard = pasteboard ?? SystemPasteboardProvider()
        self.pasteboard = resolvedPasteboard
        var snapshot: [NSPasteboard.PasteboardType: Data] = [:]
        for type in resolvedPasteboard.types {
            if let data = resolvedPasteboard.data(forType: type) {
                snapshot[type] = data
            }
        }
        savedClipboard = snapshot
    }

    func commit(text: String) throws {
        pasteboard.clearContents()
        guard pasteboard.setString(text, forType: .string) else {
            throw TunedVoiceError.pasteFailed("Failed to write text to clipboard")
        }
        guard pasteboard.string(forType: .string) == text else {
            throw TunedVoiceError.pasteFailed("Clipboard verification failed")
        }
    }

    func restore() {
        guard !savedClipboard.isEmpty else { return }
        pasteboard.clearContents()
        let item = NSPasteboardItem()
        for (type, data) in savedClipboard {
            item.setData(data, forType: type)
        }
        pasteboard.writeObjects([item])
    }
}
```

