func configureVocabularyBoosting(weightedTerms: [WeightedVocabularyItem]) async {
    let summary = makeCTCVocabularySummary(weightedTerms: weightedTerms)
    // ...
    let tokenizer: CtcTokenizer?
    if let cached = (_state.withLock { $0.ctcTokenizer }) {
        tokenizer = cached
    } else {
        do {
            let loaded = try await CtcTokenizer.load()
            _state.withLock { $0.ctcTokenizer = loaded }
            tokenizer = loaded
        } catch {
            tokenizer = nil
        }
    }
    var tokenizedOk = 0
    var skipped = 0
    let terms: [CustomVocabularyTerm] = summary.normalizedTerms.compactMap { item in
        guard let tokenizer else { skipped += 1; return nil }
        let ids = tokenizer.encode(item.text)
        guard !ids.isEmpty else { skipped += 1; return nil }
        tokenizedOk += 1
        return CustomVocabularyTerm(text: item.text, weight: Float(item.weight), ctcTokenIds: ids)
    }
}

