private func loadFromCustomFolder(_ baseDir: URL) async throws {
    let repoDir = baseDir.appendingPathComponent(repoFolderName)
    let required = ["Preprocessor.mlmodelc", "Encoder.mlmodelc", "Decoder.mlmodelc",
