    for file in required {
        let fileURL = repoDir.appendingPathComponent(file)
        guard FileManager.default.fileExists(atPath: fileURL.path) else {
            _state.withLock { $0.state = TranscriptionEngineState.error }
            throw TunedVoiceError.modelUnavailable("Missing \(file) in custom model directory")
